export function getResources() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY)
    const ver = parseInt(localStorage.getItem(VERSION_KEY) || '0', 10)
    if (raw && ver >= 2) {
      return JSON.parse(raw)
    }
    // 版本过旧或首次使用 → 重置为新种子数据
  } catch (e) {}
  setResources(SEED_DATA)
  localStorage.setItem(VERSION_KEY, '2')
  return [...SEED_DATA]
}

export function setResources(data) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data))
    localStorage.setItem(VERSION_KEY, '2')
  } catch (e) {
    console.error('保存失败:', e)
  }
}

export function addResource(item) {
  const list = getResources()
  const maxId = list.reduce((max, r) => Math.max(max, r.id || 0), 0)
  const newItem = {
    ...item,
    id: maxId + 1,
    click_count: 0,
    created_at: new Date().toISOString().slice(0, 10),
  }
  list.unshift(newItem)
  setResources(list)
  return newItem
}

export function updateResource(id, data) {
  const list = getResources()
  const idx = list.findIndex(r => r.id === id)
  if (idx === -1) return null
  list[idx] = { ...list[idx], ...data }
  setResources(list)
  return list[idx]
}

export function deleteResource(id) {
  const list = getResources().filter(r => r.id !== id)
  setResources(list)
}

export function exportData() {
  const data = getResources()
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = 
  a.click()
  URL.revokeObjectURL(url)
}

export function importData(jsonStr) {
  const data = JSON.parse(jsonStr)
  if (!Array.isArray(data)) throw new Error('数据格式错误')
  setResources(data)
  return data.length
}
